void MOD_mkSoC_Top::vcd_submodules(tVCDDumpType dt, unsigned int levels, MOD_mkSoC_Top &backing)
{
  INST_boot_rom.dump_VCD(dt, levels, backing.INST_boot_rom);
  INST_corew_plic.dump_VCD(dt, levels, backing.INST_corew_plic);
  INST_corew_proc.dump_VCD(dt, levels, backing.INST_corew_proc);
  INST_corew_soc_map.dump_VCD(dt, levels, backing.INST_corew_soc_map);
  INST_corew_tagController_tmp_tagCon.dump_VCD(dt,
					       levels,
					       backing.INST_corew_tagController_tmp_tagCon);
  INST_mem0_controller.dump_VCD(dt, levels, backing.INST_mem0_controller);
  INST_soc_map.dump_VCD(dt, levels, backing.INST_soc_map);
  INST_uart0.dump_VCD(dt, levels, backing.INST_uart0);
}
